1	type Item = {
2	  type: string;
3	  cursed?: boolean;
4	  enchantment?: number;
5	  material?: string;
6	};
7	type Customer = { yearsWithMHPCO: number };
8	type QuoteStep = { op: "quote"; items: Item[] };
9	type Damage = { itemType: string; amount: number };
10	type ClaimStep = {
11	  op: "claim";
12	  policy: number;
13	  incident: { cause: string; damages: Damage[] };
14	};
15	type Step = QuoteStep | ClaimStep;
16	type Scenario = {
17	  customer: Customer;
18	  steps: Step[];
19	};
20	
21	const PROCESSING_FEE = 5;
22	const FIRST_CONTRACT_SURCHARGE_RATE = 0.1;
23	const CURSE_SURCHARGE_RATE = 0.5;
24	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
25	const HIGH_ENCHANTMENT_THRESHOLD = 5;
26	const LOYALTY_DISCOUNT_RATE = 0.2;
27	const LOYALTY_THRESHOLD_YEARS = 2;
28	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
29	const ITEM_BASE: Record<string, number> = {
30	  sword: 100,
31	  amulet: 60,
32	  staff: 80,
33	  potion: 40,
34	  rune: 25,
35	  moonstone: 25,
36	};
37	const ITEM_INSURANCE_VALUE: Record<string, number> = {
38	  sword: 1000,
39	  amulet: 600,
40	  staff: 800,
41	  potion: 400,
42	  rune: 250,
43	  moonstone: 250,
44	};
45	const DEDUCTIBLE = 100;
46	const CAP_MULTIPLIER = 2;
47	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
48	const HIGH_ENCHANTMENT_DAMAGE_THRESHOLD = 8;
49	
50	const COMPONENT_BLOCK_SIZE = 3;
51	const COMPONENT_BLOCK_BASE = 60;
52	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
53	
54	const groupCountsByType = (items: Item[]): Map<string, number> => {
55	  const counts = new Map<string, number>();
56	  for (const item of items) {
57	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
58	  }
59	  return counts;
60	};
61	
62	const baseForGroup = (type: string, count: number): number => {
63	  if (COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE) {
64	    return COMPONENT_BLOCK_BASE;
65	  }
66	  return count * ITEM_BASE[type];
67	};
68	
69	const calculatePolicyBase = (items: Item[]): number => {
70	  let total = 0;
71	  for (const [type, count] of groupCountsByType(items)) {
72	    total += baseForGroup(type, count);
73	  }
74	  return total;
75	};
76	
77	const roundUpInMHPCOsFavor = (amount: number): number => Math.ceil(amount);
78	
79	type ItemSurcharge = { applies: (item: Item) => boolean; rate: number };
80	
81	const ITEM_SURCHARGES: ItemSurcharge[] = [
82	  { applies: (item) => item.cursed === true, rate: CURSE_SURCHARGE_RATE },
83	  {
84	    applies: (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
85	    rate: HIGH_ENCHANTMENT_SURCHARGE_RATE,
86	  },
87	];
88	
89	const surchargesForItem = (item: Item): number => {
90	  const itemBase = ITEM_BASE[item.type];
91	  return ITEM_SURCHARGES.reduce(
92	    (sum, { applies, rate }) => sum + (applies(item) ? itemBase * rate : 0),
93	    0,
94	  );
95	};
96	
97	const itemSpecificSurcharges = (items: Item[]): number =>
98	  items.reduce((sum, item) => sum + surchargesForItem(item), 0);
99	
100	type PolicyContext = { customer: Customer; quoteIndex: number };
101	
102	type PolicyModifier = {
103	  applies: (context: PolicyContext) => boolean;
104	  signedRate: number;
105	};
106	
107	const POLICY_MODIFIERS: PolicyModifier[] = [
108	  { applies: () => true, signedRate: +FIRST_CONTRACT_SURCHARGE_RATE },
109	  {
110	    applies: ({ customer }) => customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS,
111	    signedRate: -LOYALTY_DISCOUNT_RATE,
112	  },
113	  {
114	    applies: ({ quoteIndex }) => quoteIndex > 0,
115	    signedRate: -FOLLOW_UP_DISCOUNT_RATE,
116	  },
117	];
118	
119	const policyWideAdjustment = (policyBase: number, context: PolicyContext): number =>
120	  POLICY_MODIFIERS.reduce(
121	    (sum, { applies, signedRate }) => sum + (applies(context) ? policyBase * signedRate : 0),
122	    0,
123	  );
124	
125	const quotePremium = ({ items }: QuoteStep, context: PolicyContext): number => {
126	  const policyBase = calculatePolicyBase(items);
127	  return roundUpInMHPCOsFavor(
128	    policyBase +
129	      itemSpecificSurcharges(items) +
130	      policyWideAdjustment(policyBase, context) +
131	      PROCESSING_FEE,
132	  );
133	};
134	
135	const insuranceSum = (items: Item[]): number =>
136	  items.reduce((sum, item) => sum + ITEM_INSURANCE_VALUE[item.type], 0);
137	
138	const roundDownInMHPCOsFavor = (amount: number): number => Math.floor(amount);
139	
140	type Policy = { items: Item[]; remainingCap: number };
141	type QuoteResult = { premium: number };
142	type ClaimResult = { payout: number; remainingCap: number };
143	
144	const reimbursableDamage = (damage: Damage, item: Item): number =>
145	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_DAMAGE_THRESHOLD
146	    ? damage.amount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
147	    : damage.amount;
148	
149	const payoutForDamage = (damage: Damage, item: Item): number =>
150	  Math.max(reimbursableDamage(damage, item) - DEDUCTIBLE, 0);
151	
152	const findInsuredItem = (policy: Policy, itemType: string): Item =>
153	  policy.items.find((item) => item.type === itemType) as Item;
154	
155	const sumPayouts = (policy: Policy, damages: Damage[]): number =>
156	  damages.reduce(
157	    (sum, damage) => sum + payoutForDamage(damage, findInsuredItem(policy, damage.itemType)),
158	    0,
159	  );
160	
161	const validateDamagesAgainstPolicy = (policy: Policy, damages: Damage[]): void => {
162	  const insuredCounts = groupCountsByType(policy.items);
163	  const damageCounts = new Map<string, number>();
